import React from 'react'
import './modal.css'

const Modal = (props) => {
  let modalBackdrop = false
  return (
    <div className='modal-backdrop' id='modalBackdrop'>
      <div className='modal'>
        {props.children}
      </div>
    </div>
  )
}

export default Modal
